  overview:   `<svg viewBox="0 0 14 14" fill="currentColor"><rect x="0" y="0" width="5.5" height="5.5" rx="1"/><rect x="8.5" y="0" width="5.5" height="5.5" rx="1"/><rect x="0" y="8.5" width="5.5" height="5.5" rx="1"/><rect x="8.5" y="8.5" width="5.5" height="5.5" rx="1"/></svg>`,
  tracker:    `<svg viewBox="0 0 14 14" fill="none" stroke="currentColor" stroke-width="1.4" stroke-linecap="round"><line x1="1" y1="3.5" x2="13" y2="3.5"/><line x1="1" y1="7" x2="9" y2="7"/><line x1="1" y1="10.5" x2="11" y2="10.5"/></svg>`,
