// ─── SAB helpers ───────────────────────────────
function getStepAllItems(step) {
  if (step.subSections) return step.subSections.flatMap(ss => ss.items);
  return step.items || [];
}
function sabTotalItems(p) {
  return p.sabPhases.reduce((a,ph) => a + ph.steps.reduce((b,st) => b + getStepAllItems(st).length, 0), 0);
}
function sabCheckedItems(p, TS) {
  let count = 0;
  p.sabPhases.forEach((ph,pi) => ph.steps.forEach((st,si) => {
    getStepAllItems(st).forEach((_,ii) => { if (TS[`${pi}-${si}-${ii}`]) count++; });
  }));
  return count;
}
function buildReadinessPct(p, TS) {
  const total = sabTotalItems(p);
  if (!total) return p.sabProgress;
  return Math.round(sabCheckedItems(p, TS) / total * 100);
}

// ─── Sidebar builder ───────────────────────────
function buildSidebar(p, activeKey, TS) {
  TS = TS || {};
  const pct = buildReadinessPct(p, TS);
  const total = sabTotalItems(p);
  const checked = sabCheckedItems(p, TS);

  const phaseRows = p.sabPhases.map((ph,pi) => {
    const done = ph.complete || (ph.steps.length && ph.steps.every((_,si) =>
      getStepAllItems(ph.steps[si]).every((_,ii) => TS[`${pi}-${si}-${ii}`])
    ));
    const active = !done && (pi === 0 || p.sabPhases[pi-1].complete);
    const cls = done ? 'done' : active ? 'active' : '';
    const dotInner = done
      ? `<svg viewBox="0 0 8 8"><path d="M1 4l2 2 4-4" stroke="white" stroke-width="1.2" fill="none" stroke-linecap="round"/></svg>`
      : active ? `<div style="width:5px;height:5px;border-radius:50%;background:var(--green)"></div>` : '';
    return `<div class="sb-phase-row ${active?'active':''}" onclick="window.location='tracker.html'">
      <div class="sb-phase-pip ${cls}">${dotInner}</div>
      <div class="sb-phase-info">
        <div class="sb-phase-name">${ph.short}</div>
        <div class="sb-phase-status">${done ? 'Complete' : active ? 'In progress' : 'Upcoming'}</div>
      </div>
    </div>`;
  }).join('');

  const navLinks = NAV.map(n => {
    const active = n.key === activeKey;
    const badge = n.key === 'updates' && p.updates?.length
      ? `<span class="sb-nav-badge">${p.updates.length}</span>` : '';
    const urgent = n.key === 'updates' && p.decisions?.some(d => d.status === 'urgent')
      ? `<span class="sb-nav-badge urgent">!</span>` : badge;
    return `<a class="sb-nav-link ${active?'active':''}" href="${n.file}">
      <svg class="sb-nav-ico" viewBox="0 0 14 14" style="color:${active?'rgba(235,233,222,0.9)':'rgba(235,233,222,0.42)'}">${NAV_SVGS[n.key]}</svg>
      ${n.label}${urgent}
    </a>`;
  }).join('');

  return `
  <aside class="sidebar">
    <div class="sb-logo">
      <img src="${LOGO_CIRCLE}" alt="Six Arrows" style="width:36px;height:36px;object-fit:contain;flex-shrink:0">
      <div class="sb-logo-text">
        <div class="sb-logo-name">Six Arrows</div>
        <div class="sb-logo-sub">Client Portal</div>
      </div>
    </div>
    <div class="sb-project">
      <div class="sb-project-eyebrow">Your project</div>
      <div class="sb-project-name">${p.clientName}</div>
      <div class="sb-project-sub">${p.projectName} · ${p.location}</div>
    </div>
    <div class="sb-readiness" id="sb-readiness-block">
      ${activeKey === 'tracker' ? `
        <div class="sb-readiness-lbl">Build Readiness</div>
        <div class="sb-readiness-val" id="sb-pct">${pct}%</div>
        <div class="sb-track"><div class="sb-fill" id="sb-fill" style="width:${pct}%"></div></div>
        <div class="sb-readiness-sub" id="sb-sub">${checked} of ${total || '—'} steps complete</div>
      ` : p.statusType === 'construction' ? `
        <div class="sb-readiness-lbl">Construction Progress</div>
        <div class="sb-readiness-val" id="sb-pct">${p.constructionPct || 0}%</div>
        <div class="sb-track"><div class="sb-fill" id="sb-fill" style="width:${p.constructionPct || 0}%;background:#9eaa90"></div></div>
        <div class="sb-readiness-sub" id="sb-sub">Active build — ${p.phaseLabel}</div>
      ` : `
        <div class="sb-readiness-lbl">Project Status</div>
        <div style="font-size:15px;font-weight:600;color:var(--cream);margin:4px 0 6px;line-height:1.2" id="sb-pct">${p.status}</div>
        <div class="sb-readiness-sub" id="sb-sub">${p.phaseLabel}</div>
      `}
    </div>
    <div class="sb-phases">
      <div class="sb-section-lbl">Phases</div>
      ${phaseRows}
    </div>
    <nav class="sb-nav">
      <div class="sb-section-lbl" style="padding:0 2px;margin-bottom:6px">Navigate</div>
      ${navLinks}
    </nav>
    <div class="sb-footer">
      <div class="sb-contact">
        Questions? Reach out anytime.<br>
        <strong>${p.teamLead}</strong> · ${p.teamPhone}<br>
        ${p.teamEmail}
      </div>
      <div class="sb-logout" onclick="AUTH.logout()">
        <svg viewBox="0 0 12 12"><path d="M4 1H2a1 1 0 00-1 1v8a1 1 0 001 1h2M7 8.5L10 6l-3-2.5M4 6h6"/></svg>
        Sign out
      </div>
    </div>
  </aside>`;
}

// ─── Topbar builder ────────────────────────────
function buildTopbar(p, pageLabel) {
  const urgent = p.decisions?.find(d => d.status === 'urgent');
  return `<div class="topbar">
    <div class="topbar-crumb">
      <span>${p.clientName}</span>
      <span class="sep">›</span>
      <span class="page">${pageLabel}</span>
    </div>
    <div class="topbar-right">
      ${urgent ? `<div class="topbar-urgent"><div class="urgdot"></div>Decision needed: ${urgent.title} — Due ${urgent.due}</div>` : ''}
    </div>
  </div>`;
}

