// ─── Mount layout ──────────────────────────────
function mountLayout(activeKey, pageLabel, contentHtml, TS) {
  const p = AUTH.requireAuth();
  if (!p) return null;
  document.body.innerHTML = `
    <canvas id="confetti-canvas"></canvas>
    <div class="toast-wrap" id="toast-wrap"></div>
    <div class="modal-overlay" id="modal-overlay">
      <div class="modal-box">
        <img class="modal-logo" id="modal-logo" src="${LOGO_CIRCLE}" alt="Six Arrows">
        <div class="modal-title"  id="modal-title">Milestone Reached</div>
        <p  class="modal-body"   id="modal-body">You have completed a major phase of your build journey.</p>
        <div class="modal-badge" id="modal-badge">Phase Complete</div>
        <br><br>
        <button class="modal-btn" onclick="closeModal()">Continue →</button>
      </div>
    </div>
    <div class="shell">
      ${buildSidebar(p, activeKey, TS)}
      <div class="main-wrap">
        ${buildTopbar(p, pageLabel)}
        <div class="page-content">${contentHtml}</div>
      </div>
    </div>
    ${buildMobileNav(activeKey)}`;
  return p;
}

// ─── Toast ─────────────────────────────────────
function showToast(msg, type) {
  const wrap = document.getElementById('toast-wrap');
  if (!wrap) return;
  const t = document.createElement('div');
  t.className = 'toast' + (type==='milestone' ? ' milestone' : '');
  t.textContent = msg;
  wrap.appendChild(t);
  requestAnimationFrame(() => requestAnimationFrame(() => t.classList.add('show')));
  setTimeout(() => { t.classList.remove('show'); setTimeout(() => t.remove(), 300); }, 3200);
}

// ─── Milestone modal ───────────────────────────
function showMilestoneModal(title, body, badge) {
  document.getElementById('modal-title').textContent = title;
  document.getElementById('modal-body').textContent  = body;
  document.getElementById('modal-badge').textContent = '✦  ' + badge;
  document.getElementById('modal-overlay').classList.add('show');
  launchConfetti();
}
function closeModal() {
  document.getElementById('modal-overlay').classList.remove('show');
}

// ─── Confetti ──────────────────────────────────
function launchConfetti() {
  const canvas = document.getElementById('confetti-canvas');
  if (!canvas) return;
  const ctx = canvas.getContext('2d');
  canvas.width  = window.innerWidth;
  canvas.height = window.innerHeight;
  const pal = ['#757f69','#5a6350','#3d4535','#ebe9de','#d4d0c0','#2e2e2e','#eaede6','#a0aa94'];
  const pieces = Array.from({length:120}, () => ({
    x: Math.random() * canvas.width,
    y: -8 - Math.random() * 50,
    w: 7 + Math.random() * 7, h: 10 + Math.random() * 5,
    color: pal[Math.floor(Math.random() * pal.length)],
    vx: (Math.random()-0.5) * 2.4, vy: 2 + Math.random() * 2.5,
    rot: Math.random() * 360, vr: (Math.random()-0.5) * 5.5,
    life: 1,
  }));
  let frame = 0;
  (function draw() {
    ctx.clearRect(0,0,canvas.width,canvas.height);
    pieces.forEach(p => {
      ctx.save();
      ctx.translate(p.x, p.y);
      ctx.rotate(p.rot * Math.PI / 180);
      ctx.globalAlpha = p.life;
      ctx.fillStyle = p.color;
      ctx.fillRect(-p.w/2, -p.h/2, p.w, p.h);
      ctx.restore();
      p.x += p.vx; p.y += p.vy; p.rot += p.vr; p.vy += 0.055;
      if (frame > 65) p.life -= 0.015;
    });
    frame++;
    if (frame < 150) requestAnimationFrame(draw);
    else ctx.clearRect(0,0,canvas.width,canvas.height);
  })();
}

// ─── Decision tag ──────────────────────────────
function decTag(status) {
  if (status === 'urgent') return '<span class="tag danger">Urgent</span>';
  if (status === 'active') return '<span class="tag warn">Active</span>';
  return '<span class="tag neutral">Queued</span>';
}
